import React, { useState } from "react";
import axios from "axios";
import { Line } from "react-chartjs-2";
import AffiliateBanner from "./AffiliateBanner";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend, Filler);

const formatCurrency = (value) => {
  if (value == null) return "N/A";
  return `₹${Number(value).toLocaleString("en-IN")}`;
};

const formatNumber = (value, decimals = 2) => {
  if (value == null) return "N/A";
  return Number(value).toFixed(decimals);
};

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchData = async () => {
    setError("");
    setLoading(true);
    setData(null);

    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch stock data.");
    } finally {
      setLoading(false);
    }
  };

  const renderMetricCard = (label, value, isCurrency = false) => {
    const displayValue = isCurrency ? formatCurrency(value) : formatNumber(value);

    return (
      <div
        key={label}
        style={{
          background: "#f9f9fb",
          padding: "15px",
          borderRadius: "8px",
          boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
          flex: "1 1 200px",
          margin: "10px",
          transition: "transform 0.3s",
        }}
        className="metric-card"
      >
        <div style={{ color: "#888", fontSize: "14px", marginBottom: "5px" }}>{label}</div>
        <div style={{ fontSize: "18px", fontWeight: "bold", color: "#007bff" }}>{displayValue}</div>
      </div>
    );
  };

  const renderChart = () => {
    if (!data?.historical?.length) return null;

    const labels = data.historical.map((d) =>
      new Date(d.date).toLocaleDateString("en-IN", { month: "short", day: "numeric" })
    );
    const prices = data.historical.map((d) => d.close);

    return (
      <div style={{ marginTop: "30px" }}>
        <h4 style={{ marginBottom: "10px" }}>📈 Price Trend</h4>
        <Line
          data={{
            labels,
            datasets: [
              {
                label: `${data.symbol} Closing Price`,
                data: prices,
                borderColor: "#007bff",
                backgroundColor: "rgba(0, 123, 255, 0.1)",
                tension: 0.3,
                fill: true,
              },
            ],
          }}
          options={{
            responsive: true,
            plugins: {
              legend: { display: false },
              tooltip: {
                callbacks: {
                  label: (ctx) => `₹${ctx.parsed.y}`,
                },
              },
            },
            scales: {
              y: {
                ticks: {
                  callback: (value) => `₹${value}`,
                },
              },
            },
          }}
        />
      </div>
    );
  };

  const metricList = [
    { label: "EPS", key: "eps" },
    { label: "ROE (%)", key: "roe" },
    { label: "Book Value", key: "bookValue", currency: true },
    { label: "Face Value", key: "faceValue", currency: true },
    { label: "PE Ratio", key: "peRatio" },
    { label: "Dividend Yield (%)", key: "dividendYield" },
    { label: "ROCE (%)", key: "roce" },
    { label: "Market Cap", key: "marketCap", currency: true },
    { label: "52 Week High", key: "fiftyTwoWeekHigh", currency: true },
    { label: "52 Week Low", key: "fiftyTwoWeekLow", currency: true },
  ];

  const renderList = (arr, emptyMsg) =>
    arr && arr.length > 0 ? (
      <ul style={{ paddingLeft: "20px" }}>
        {arr.map((item, i) => (
          <li key={i} style={{ marginBottom: "5px" }}>{item}</li>
        ))}
      </ul>
    ) : (
      <p style={{ color: "gray", fontStyle: "italic" }}>{emptyMsg}</p>
    );

  return (
    <div
      style={{
        padding: "20px",
        maxWidth: "1200px",
        margin: "0 auto",
        fontFamily: "Arial, sans-serif",
      }}
    >
      <h2 style={{ color: "#007bff", marginBottom: "20px", textAlign: "center" }}>
        📈 Indian Stock Details
      </h2>
      <div style={{ marginBottom: "20px", display: "flex", justifyContent: "center" }}>
        <input
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          placeholder="Enter Symbol (e.g., TCS.NS)"
          style={{
            padding: "10px",
            width: "250px",
            marginRight: "10px",
            borderRadius: "4px",
            border: "1px solid #ccc",
            fontSize: "16px",
          }}
        />
        <button
          onClick={fetchData}
          disabled={loading}
          style={{
            padding: "10px 20px",
            backgroundColor: "#007bff",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
            fontSize: "16px",
          }}
        >
          {loading ? "Loading..." : "Get Details"}
        </button>
      </div>

      {loading && (
        <div style={{ textAlign: "center", marginTop: "30px" }}>
          <div className="loader" />
        </div>
      )}

      {error && <p style={{ color: "red", textAlign: "center" }}>{error}</p>}

      {data && (
        <>
          <h3 style={{ textAlign: "center" }}>
            {data.name} ({data.symbol})
          </h3>
          <h1
            style={{
              color: data.change > 0 ? "#28a745" : "#dc3545",
              textAlign: "center",
              margin: "10px 0",
            }}
          >
            ₹{formatNumber(data.price)} | Change: {formatNumber(data.change)} ({formatNumber(data.percentChange)}%)
          </h1>

          <div style={{ display: "flex", flexWrap: "wrap", margin: "20px -10px" }}>
            {metricList.map((metric) =>
              renderMetricCard(metric.label, data[metric.key], metric.currency)
            )}
          </div>

          {renderChart()}

          <h4 style={{ marginTop: "30px" }}>👨‍👩‍👧‍👦 Peers</h4>
          {renderList(data.peers, "No peer data available.")}

          <h4 style={{ marginTop: "20px" }}>✅ Pros</h4>
          {renderList(data.pros, "No pros found.")}

          <h4 style={{ marginTop: "20px" }}>❌ Cons</h4>
          {renderList(data.cons, "No cons found.")}

          <h4 style={{ marginTop: "30px" }}>📄 Balance Sheet</h4>
          {data.balanceSheet?.length > 0 ? (
            <table className="styled-table">
              <thead>
                <tr>
                  <th>Year</th>
                  <th>Total Assets</th>
                  <th>Total Liabilities</th>
                  <th>Equity</th>
                </tr>
              </thead>
              <tbody>
                {data.balanceSheet.map((item, i) => (
                  <tr key={i}>
                    <td>{item.year}</td>
                    <td>{formatCurrency(item.assets)}</td>
                    <td>{formatCurrency(item.liabilities)}</td>
                    <td>{formatCurrency(item.equity)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p>No balance sheet data.</p>
          )}

          <h4 style={{ marginTop: "30px" }}>📄 Profit & Loss</h4>
          {data.profitLoss?.length > 0 ? (
            <table className="styled-table">
              <thead>
                <tr>
                  <th>Year</th>
                  <th>Revenue</th>
                  <th>Profit</th>
                </tr>
              </thead>
              <tbody>
                {data.profitLoss.map((item, i) => (
                  <tr key={i}>
                    <td>{item.year}</td>
                    <td>{formatCurrency(item.revenue)}</td>
                    <td>{formatCurrency(item.profit)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p>No profit & loss data.</p>
          )}
        </>
      )}
      <AffiliateBanner />
      <style>{`
        .metric-card:hover {
          transform: scale(1.05);
        }
        .styled-table {
          width: 100%;
          border-collapse: collapse;
          margin: 20px 0;
          font-size: 16px;
        }
        .styled-table th, .styled-table td {
          padding: 12px;
          border: 1px solid #ddd;
          text-align: center;
        }
        .styled-table thead {
          background-color: #007bff;
          color: #fff;
        }
        .styled-table tbody tr:nth-child(even) {
          background-color: #f9f9f9;
        }
        .loader {
          border: 8px solid #f3f3f3;
          border-top: 8px solid #007bff;
          border-radius: 50%;
          width: 60px;
          height: 60px;
          animation: spin 1s linear infinite;
          margin: auto;
        }
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default IndianStockDetails;
